class _PigeonCodec extends StandardMessageCodec {
  const _PigeonCodec();
  @override
  void writeValue(WriteBuffer buffer, Object? value) {
    if (value is int) {
      buffer.putUint8(4);
      buffer.putInt64(value);
    }    else if (value is PyrxEventKind) {
      buffer.putUint8(129);
      writeValue(buffer, value.index);
    }    else if (value is PyrxInitArgs) {
      buffer.putUint8(130);
      writeValue(buffer, value.encode());
    }    else if (value is PyrxIdentityResult) {
      buffer.putUint8(131);
      writeValue(buffer, value.encode());
    }    else if (value is PyrxPushPermissionResult) {
      buffer.putUint8(132);
      writeValue(buffer, value.encode());
    }    else if (value is PyrxDebugInfo) {
      buffer.putUint8(133);
      writeValue(buffer, value.encode());
    }    else if (value is PushReceivedEventDto) {
      buffer.putUint8(134);
      writeValue(buffer, value.encode());
    }    else if (value is PushClickedEventDto) {
      buffer.putUint8(135);
      writeValue(buffer, value.encode());
    }    else if (value is IdentitySnapshotDto) {
      buffer.putUint8(136);
      writeValue(buffer, value.encode());
    }    else if (value is QueueDrainedEventDto) {
      buffer.putUint8(137);
      writeValue(buffer, value.encode());
    }    else if (value is IdentityChangedEventDto) {
      buffer.putUint8(138);
      writeValue(buffer, value.encode());
    }    else if (value is InAppCtaDto) {
      buffer.putUint8(139);
      writeValue(buffer, value.encode());
    }    else if (value is InAppMessageDto) {
      buffer.putUint8(140);
      writeValue(buffer, value.encode());
    }    else if (value is InAppMessageReceivedEventDto) {
      buffer.putUint8(141);
      writeValue(buffer, value.encode());
    }    else if (value is InAppMessageDismissedEventDto) {
      buffer.putUint8(142);
      writeValue(buffer, value.encode());
    }    else if (value is InAppShowTokenDto) {
      buffer.putUint8(143);
      writeValue(buffer, value.encode());
    }    else if (value is PyrxEventEnvelope) {
      buffer.putUint8(144);
      writeValue(buffer, value.encode());
    } else {
      super.writeValue(buffer, value);
    }
  }

  @override
  Object? readValueOfType(int type, ReadBuffer buffer) {
    switch (type) {
      case 129:
        final value = readValue(buffer) as int?;
        return value == null ? null : PyrxEventKind.values[value];
      case 130:
        return PyrxInitArgs.decode(readValue(buffer)!);
      case 131:
        return PyrxIdentityResult.decode(readValue(buffer)!);
      case 132:
        return PyrxPushPermissionResult.decode(readValue(buffer)!);
      case 133:
        return PyrxDebugInfo.decode(readValue(buffer)!);
      case 134:
        return PushReceivedEventDto.decode(readValue(buffer)!);
      case 135:
        return PushClickedEventDto.decode(readValue(buffer)!);
      case 136:
        return IdentitySnapshotDto.decode(readValue(buffer)!);
      case 137:
        return QueueDrainedEventDto.decode(readValue(buffer)!);
      case 138:
        return IdentityChangedEventDto.decode(readValue(buffer)!);
      case 139:
        return InAppCtaDto.decode(readValue(buffer)!);
      case 140:
        return InAppMessageDto.decode(readValue(buffer)!);
      case 141:
        return InAppMessageReceivedEventDto.decode(readValue(buffer)!);
      case 142:
